import { scaleOrdinal } from 'd3-scale';

import { getValidColor } from './getValidColor.js';
import { SCALE_FALLBACK_COLOR } from '../constants.js';
import {
  isCustomColorPalette,
  type ColorPalette,
  type CustomColorPalette,
} from '../types/color-palette.js';
import { colorPaletteMap } from '../types/color-palettes-definitions.js';

function assignColorsToCategories(
  colorScheme: { [key: string]: string },
  categories: string[],
) {
  const assignedColors: Record<string, string> = {};

  categories.forEach((category) => {
    assignedColors[category] = getValidColor(colorScheme[category]);
  });

  return assignedColors;
}

/**
 * Builds a categorical color scale using a color palette.
 *
 * @param colorPalette - The color palette to use for the scale.
 * @param filter - The optional filter for the scale. If not provided, it will use the keys from the color palette.
 * @returns - A categorical color scale with the specified domain and color palette.
 */
export function buildCategoricalColorScale(
  colorPalette: ColorPalette | CustomColorPalette,
  filter: string[] | undefined = undefined,
) {
  if (isCustomColorPalette(colorPalette)) {
    return buildScaleWithCustomPalette(colorPalette, filter);
  }

  return buildScaleWithPalette(colorPalette, filter);
}

/**
 * Builds a scale with a predefined color palette.
 *
 * @param colorPalette - The predefined color palette to use for the scale.
 * @param filter - The optional filter for categories. If not provided, it will use all categories from the color palette.
 * @returns - A categorical color scale with the specified domain and color palette.
 */
function buildScaleWithPalette(
  colorPalette: ColorPalette,
  filter: string[] | undefined,
) {
  const categories = filter ?? Object.keys(colorPaletteMap[colorPalette]);
  const colors: string[] = [];
  const colorsList = Object.values(colorPaletteMap[colorPalette]);

  categories.forEach((dataName, i) => {
    const index = i % colorsList.length;
    const colorToken =
      colorPaletteMap[colorPalette][dataName.toLowerCase()] ??
      colorsList[index];
    if (colorToken !== undefined) {
      colors.push(colorToken.Default);
    }
  });

  return scaleOrdinal(categories, colors).unknown(SCALE_FALLBACK_COLOR);
}

/**
 * Builds a scale with a custom color palette.
 *
 * @param filter - The optional filter for the scale. If not provided, it will use the keys from the color palette.
 * @param colorPalette - The custom color palette to use for the scale.
 * @returns - A categorical color scale with the specified domain and custom color palette.
 */
function buildScaleWithCustomPalette(
  colorPalette: CustomColorPalette,
  filter: string[] | undefined,
) {
  if (Array.isArray(colorPalette)) {
    const categories = filter ?? Object.keys(colorPalette);
    return scaleOrdinal(categories, colorPalette).unknown(SCALE_FALLBACK_COLOR);
  }

  const categories = filter ?? Object.keys(colorPalette);
  const coloredCategories = assignColorsToCategories(colorPalette, categories);
  const labels = Object.keys(coloredCategories);
  const colors = Object.values(coloredCategories);

  return scaleOrdinal(labels, colors).unknown(SCALE_FALLBACK_COLOR);
}
